  .create i {
    margin-right: 5px;
  }

  button {
    font-size: 1.143em;
    padding: 8px 10px;
    vertical-align: top;
    background: transparent;
    border: none;
    margin-left: 3px;
    transition: all linear 0.15s;

        &:hover {
          background: dark-light-diff($primary, $secondary, 90%, -60%);
          color: $primary;
        }

        &:active {
          box-shadow: inset 0 1px 3px rgba(0,0,0, .4);
        }

        &.hidden {
