    color: rgba(dark-light-diff($primary, $secondary, 90%, -65%) , .8);
    font: 6.429em/1 FontAwesome;
    content: "\f014";
    z-index: -5;
}

.topic-meta-data {

 &:after {
    visibility: hidden;
    display: block;
    font-size: 0;
    content: " ";
    clear: both;
    height: 0;
 }

 .post-info  {
   display: inline-block;
   float: right;
   font-size: 0.929em;
   margin-top: 1px;
   a {color: dark-light-choose(scale-color($primary, $lightness: 50%), scale-color($secondary, $lightness: 50%)); }
 }

}

.who-liked {
