/* Tablet (portrait) ----------- */


@media all
and (max-width : 870px) {

  .gutter {
    display: none;
    }

  .topic-avatar {
    width: 45px;
  }

  .post-cloak .reply-to-tab {
      right: 15%;
    }

  .topic-body {
      box-sizing: border-box;
      width: calc(100% - 47px); //100% - [width of .topic-avatar + 2px]

