    // top means "in reply to expansion" above a post
    &.top {
      width: calc(100% - 56px); // [100% - margin-left]
    }
  }

}



/* below standard tablet portrait ----------- */

@media all
and (max-width : 767px) {

  .reply-to-tab {
    span {display: none;}
  }
  .names {
    span {display: block;}
  }

}
