    text-align: left;
    padding: 5px;
  }

  td {
    padding: 5px;
  }

  td.key {
    font-size: 0.857em;
  }
}

.dashboard-stats {
  margin-bottom: 30px;
  margin-right: 40px;
  h4 {
    font-weight: normal;
    margin-bottom: 8px;
  }

  table {
    width: 100%;

    .title {
      i.fa {
        color: $primary;
      }
      i.fa-heart {
        color: $love;
      }
    }

    th {
      font-weight: normal;
      text-align: center;
      background: dark-light-diff($primary, $secondary, 80%, -65%);
    }
    th.title {
      text-align: left;
    }
    thead {
      tr:hover > td {
        background-color: $secondary;
      }
    }

    td.value {
      font-weight: bold;
      text-align: center;

      i {
        display: none;
      }

      &.trending-up {
        i.up {
          color: $success;
          display: inline;
        }
      }
      &.trending-down {
        i.down {
          color: $danger;
          display: inline;
        }
      }
      &.no-change {
        i.down {
          display: inline;
          visibility: hidden;
        }
